[DataContract]
class PwcSLMInventTransSyncDataContract
{   
    ItemId              itemNo;    
    InventTransRefId    documentNo, referenceNo;
    InventLocationId    locationCode;
    Description         description;
    String10            reasonCode;
    InventQty           quantity;
    TransDate           postingDate;
    Amount              unitCost;
    String50            entryType;

}

